# incident_response.py — incident tracking with deadline enforcement

import json, datetime
from dataclasses import dataclass, field
from typing import Optional

NOTIFICATION_DEADLINES = {
    "HIPAA_BREACH": 60,       # calendar days
    "HIPAA_500_PLUS": 60,     # + media notification same day as individual
    "EU_AI_ACT_ART73": 15,    # calendar days
    "SEC_8K": 4,              # business days from materiality determination
    "CCPA": 45,               # calendar days (CA AG guidance)
    "GDPR_ART33": 3,          # calendar days (72 hours)
    "NY_SHIELD": 30,          # calendar days
}

@dataclass
class Incident:
    id: str
    description: str
    discovered_at: datetime.datetime
    applicable_regulations: list[str] = field(default_factory=list)
    notifications_sent: dict = field(default_factory=dict)

    def deadlines(self) -> dict[str, datetime.date]:
        result = {}
        for reg in self.applicable_regulations:
            days = NOTIFICATION_DEADLINES.get(reg)
            if days:
                result[reg] = (self.discovered_at + datetime.timedelta(days=days)).date()
        return result

    def overdue(self) -> list[str]:
        today = datetime.date.today()
        return [
            reg for reg, deadline in self.deadlines().items()
            if deadline < today and reg not in self.notifications_sent
        ]

    def status_report(self) -> dict:
        today = datetime.date.today()
        return {
            "incident_id": self.id,
            "discovered": self.discovered_at.isoformat(),
            "deadlines": {k: v.isoformat() for k, v in self.deadlines().items()},
            "notifications_sent": self.notifications_sent,
            "overdue": self.overdue(),
            "days_since_discovery": (today - self.discovered_at.date()).days,
        }

def record_notification_sent(incident: Incident, regulation: str, channel: str, reference: str):
    incident.notifications_sent[regulation] = {
        "sent_at": datetime.datetime.utcnow().isoformat() + "Z",
        "channel": channel,
        "reference": reference,
    }
    print(f"Notification recorded: {regulation} via {channel} (ref: {reference})")
